//! fp32 safetensors `WeightBackend` for the native Whisper mesh baseline.
//!
//! Reference: arXiv 2212.04356 (Whisper — Robust Speech Recognition via
//! Large-Scale Weak Supervision, Radford et al. 2022).
//! https://arxiv.org/abs/2212.04356
//!
//! This is the *native proof* loader for the gnosis Whisper engine. It reads an
//! HF `model.safetensors` (the canonical OpenAI/HF Whisper checkpoint), maps
//! the HF tensor names to the gnosis `encoder_blk_{i}_*` / `decoder_blk_{i}_*`
//! convention (see [`crate::loader_whisper`]), dequantizes F16→F32 where
//! needed, and serves the resulting little-endian f32 bytes through the
//! [`WeightBackend`] trait — the same trait the mmap / HTTP / wasm-host
//! backends implement, so the encoder + decoder are byte-identical downstream.
//!
//! The HF→gnosis name map mirrors the one proven by the `wasm-modules/voice-stt`
//! crate (`src/weights.rs::map_hf_to_gnosis`), which is the loader that already
//! transcribes the fox correctly in-browser.
//!
//! ## Weight-density forward-compatibility (mesh: smallest knot wins)
//!
//! The mesh wants the SMALLEST possible weights knot — R2 storage, Range-stream
//! bandwidth, and per-node memory all scale with it. fp32 is the *correctness*
//! baseline, not the wire format. A dense GKQ knot (rank-k SVD, validated
//! separately) is the intended production format. To keep that path open WITHOUT
//! implementing it here, this backend is built around a [`WeightSource`] enum:
//! the fp32-safetensors variant materializes every tensor up front; a future
//! `Gkq { ... }` variant can dequantize lazily on `fetch_tensor`. The encoder /
//! decoder never see the difference — they only know the gnosis tensor names
//! and the `WeightBackend` trait. See [`WeightSource`] for the slot.

use std::collections::HashMap;
use std::sync::Arc;

use crate::loader::{OwnedBytes, WeightBackend};
use crate::loader_whisper::WhisperConfig;

// ─────────────────────────────────────────────────────────────────────────
// WeightSource — the density slot
// ─────────────────────────────────────────────────────────────────────────

/// Where a Whisper tensor's f32 bytes come from.
///
/// The native baseline only uses [`WeightSource::DenseF32`]: every gnosis-named
/// tensor is pre-materialized as little-endian f32 in a map. This is the
/// correctness ground-truth.
///
/// The mesh production path will add density variants that defer dequantization
/// to `fetch_tensor` (so a node only pays to expand the tensors it actually
/// touches, and the on-wire / on-R2 knot stays small):
///
///   * `Gkq { manifest, payload }` — dense rank-k SVD GKQ knot. A
///     `fetch_tensor(name)` would look up the tensor's rank-k factors
///     `(U_k, S_k, V_k^T)` in `manifest`, reconstruct `W ≈ U_k diag(S_k) V_k^T`
///     into an f32 buffer, and return it. NOT implemented here — the enum
///     variant is the documented seam so adding it later is a pure addition,
///     no churn to the encoder/decoder or this backend's public shape.
///
/// Keeping the seam explicit (rather than hardcoding a `HashMap<String,
/// Vec<f32>>`) is the "don't preclude GKQ" requirement made structural.
pub enum WeightSource {
    /// Fully-materialized fp32 tensors, keyed by gnosis tensor name.
    DenseF32(HashMap<String, Arc<Vec<u8>>>),
    // Gkq { manifest: GkqManifest, payload: Arc<Vec<u8>> },  // future: rank-k SVD
}

// ─────────────────────────────────────────────────────────────────────────
// SafetensorsWhisperBackend
// ─────────────────────────────────────────────────────────────────────────

/// A [`WeightBackend`] backed by an HF Whisper `model.safetensors`.
///
/// Construct with [`SafetensorsWhisperBackend::from_safetensors_bytes`], then
/// hand the resulting `Arc<dyn WeightBackend>` to
/// [`crate::wasm_bindings_whisper::WhisperPipelineInner::new`] (native) or the
/// encoder/decoder directly.
pub struct SafetensorsWhisperBackend {
    source: WeightSource,
    config: WhisperConfig,
}

impl SafetensorsWhisperBackend {
    /// Parse HF `model.safetensors` bytes (fp32 or fp16) into a native
    /// gnosis-named fp32 weight backend, plus the auto-detected
    /// [`WhisperConfig`].
    ///
    /// Returns `(backend, config)` so the caller can build the pipeline with
    /// the exact dims the checkpoint carries (tiny / base / small / medium /
    /// large / turbo all detected from tensor shapes — no hardcoded size).
    pub fn from_safetensors_bytes(
        bytes: &[u8],
    ) -> Result<(SafetensorsWhisperBackend, WhisperConfig), String> {
        let (hf, shapes) = parse_safetensors(bytes)?;
        let config = detect_config(&shapes)?;
        let tensors = map_hf_to_gnosis(&hf, &config)?;
        let backend = SafetensorsWhisperBackend {
            source: WeightSource::DenseF32(tensors),
            config: config.clone(),
        };
        Ok((backend, config))
    }

    /// The config auto-detected from the checkpoint's tensor shapes.
    pub fn config(&self) -> &WhisperConfig {
        &self.config
    }
}

impl WeightBackend for SafetensorsWhisperBackend {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        match &self.source {
            WeightSource::DenseF32(map) => map
                .get(name)
                .map(|arc| OwnedBytes::Owned(Arc::clone(arc)))
                .ok_or_else(|| format!("SafetensorsWhisperBackend: no tensor `{name}`")),
        }
    }

    fn has_tensor(&self, name: &str) -> bool {
        match &self.source {
            WeightSource::DenseF32(map) => map.contains_key(name),
        }
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

// ─────────────────────────────────────────────────────────────────────────
// safetensors parsing
// ─────────────────────────────────────────────────────────────────────────

/// Parse a safetensors buffer into (gnosis-agnostic HF-named f32 tensors,
/// HF-named shapes). Supports F32 and F16 dtypes; rejects everything else so
/// the correctness-first path never silently runs on the wrong layout.
fn parse_safetensors(
    bytes: &[u8],
) -> Result<(HashMap<String, Vec<f32>>, HashMap<String, Vec<usize>>), String> {
    if bytes.len() < 8 {
        return Err("safetensors: buffer shorter than 8-byte header length".into());
    }
    let header_len = u64::from_le_bytes(bytes[0..8].try_into().unwrap()) as usize;
    let header_end = 8 + header_len;
    if bytes.len() < header_end {
        return Err(format!(
            "safetensors: header length {header_len} exceeds buffer {}",
            bytes.len()
        ));
    }
    let header_json = std::str::from_utf8(&bytes[8..header_end])
        .map_err(|e| format!("safetensors: header not utf8: {e}"))?;
    let header: serde_json::Value =
        serde_json::from_str(header_json).map_err(|e| format!("safetensors: header json: {e}"))?;
    let obj = header
        .as_object()
        .ok_or_else(|| "safetensors: header is not an object".to_string())?;

    let data = &bytes[header_end..];

    let mut hf: HashMap<String, Vec<f32>> = HashMap::with_capacity(obj.len());
    let mut shapes: HashMap<String, Vec<usize>> = HashMap::with_capacity(obj.len());

    for (name, meta) in obj.iter() {
        if name == "__metadata__" {
            continue;
        }
        let shape: Vec<usize> = meta
            .get("shape")
            .and_then(|v| v.as_array())
            .map(|arr| {
                arr.iter()
                    .map(|v| v.as_u64().unwrap_or(0) as usize)
                    .collect()
            })
            .unwrap_or_default();
        shapes.insert(name.clone(), shape);

        let dtype = meta
            .get("dtype")
            .and_then(|v| v.as_str())
            .ok_or_else(|| format!("safetensors: {name} missing dtype"))?;
        let offsets = meta
            .get("data_offsets")
            .and_then(|v| v.as_array())
            .ok_or_else(|| format!("safetensors: {name} missing data_offsets"))?;
        let start = offsets[0].as_u64().unwrap() as usize;
        let end = offsets[1].as_u64().unwrap() as usize;
        if end > data.len() {
            return Err(format!(
                "safetensors: {name} data_offsets end {end} exceeds data region {}",
                data.len()
            ));
        }
        let raw = &data[start..end];
        let vals = match dtype {
            "F32" => bytes_to_f32_vec(raw),
            "F16" => f16_bytes_to_f32_vec(raw),
            "BF16" => bf16_bytes_to_f32_vec(raw),
            other => {
                return Err(format!(
                    "safetensors: tensor {name} has unsupported dtype {other} \
                     (correctness-first build wants F32 / F16 / BF16)"
                ));
            }
        };
        hf.insert(name.clone(), vals);
    }

    Ok((hf, shapes))
}

// ─────────────────────────────────────────────────────────────────────────
// config auto-detection (from tensor shapes — no hardcoded size)
// ─────────────────────────────────────────────────────────────────────────

/// Count contiguous `model.{stage}.layers.{i}.*` blocks present in `shapes`.
fn count_layers(shapes: &HashMap<String, Vec<usize>>, prefix: &str) -> usize {
    let pat = format!("{prefix}.");
    let mut max_idx: Option<usize> = None;
    for name in shapes.keys() {
        if let Some(rest) = name.strip_prefix(&pat) {
            let idx_str: String = rest.chars().take_while(|c| c.is_ascii_digit()).collect();
            if let Ok(idx) = idx_str.parse::<usize>() {
                max_idx = Some(max_idx.map_or(idx, |m| m.max(idx)));
            }
        }
    }
    max_idx.map_or(0, |m| m + 1)
}

/// Derive a [`WhisperConfig`] purely from the checkpoint's tensor shapes.
fn detect_config(shapes: &HashMap<String, Vec<usize>>) -> Result<WhisperConfig, String> {
    let need = |n: &str| -> Result<&Vec<usize>, String> {
        shapes
            .get(n)
            .ok_or_else(|| format!("detect_config: missing tensor `{n}` for dim inference"))
    };

    // conv1.weight: (hidden, n_mels, 3)
    let conv1 = need("model.encoder.conv1.weight")?;
    if conv1.len() != 3 {
        return Err(format!(
            "detect_config: conv1.weight rank {} != 3",
            conv1.len()
        ));
    }
    let hidden = conv1[0];
    let n_mels = conv1[1];

    // embed_positions.weight: (n_audio_ctx, hidden)
    let enc_pos = need("model.encoder.embed_positions.weight")?;
    let n_audio_ctx = enc_pos[0];

    // fc1.weight: (inter, hidden)
    let enc_fc1 = need("model.encoder.layers.0.fc1.weight")?;
    let encoder_inter = enc_fc1[0];
    let dec_fc1 = need("model.decoder.layers.0.fc1.weight")?;
    let decoder_inter = dec_fc1[0];

    // decoder positional table → n_text_ctx; token embed → vocab.
    let dec_pos = need("model.decoder.embed_positions.weight")?;
    let n_text_ctx = dec_pos[0];
    let tok_embed = need("model.decoder.embed_tokens.weight")?;
    let vocab_size = tok_embed[0];

    let encoder_layers = count_layers(shapes, "model.encoder.layers");
    let decoder_layers = count_layers(shapes, "model.decoder.layers");
    if encoder_layers == 0 || decoder_layers == 0 {
        return Err(format!(
            "detect_config: found {encoder_layers} encoder / {decoder_layers} decoder layers"
        ));
    }

    // Heads aren't in the weight shapes; whisper uses head_dim=64 universally,
    // so heads = hidden / 64 (tiny:6, base:8, small:12, medium:16, large:20).
    let heads = (hidden / 64).max(1);

    Ok(WhisperConfig {
        n_mels,
        n_audio_ctx,
        encoder_layers,
        encoder_hidden_dim: hidden,
        encoder_heads: heads,
        encoder_intermediate_size: encoder_inter,
        decoder_layers,
        decoder_hidden_dim: hidden,
        decoder_heads: heads,
        decoder_intermediate_size: decoder_inter,
        n_text_ctx,
        vocab_size,
        eps: 1e-5,
    })
}

// ─────────────────────────────────────────────────────────────────────────
// HF → gnosis name map  (mirrors voice-stt::weights::map_hf_to_gnosis)
// ─────────────────────────────────────────────────────────────────────────

/// Build the gnosis-named, f32-bytes tensor map from the HF-named f32 map.
///
/// gnosis tensor names follow [`crate::loader_whisper::whisper_tensor_name`]
/// (`encoder_blk_{i}_<role>` etc.). Each value is stored as little-endian f32
/// bytes inside an `Arc<Vec<u8>>` so `fetch_tensor` is a zero-copy
/// `Arc::clone` and the encoder/decoder `bytes_to_f32_slice` view it directly.
fn map_hf_to_gnosis(
    hf: &HashMap<String, Vec<f32>>,
    cfg: &WhisperConfig,
) -> Result<HashMap<String, Arc<Vec<u8>>>, String> {
    let mut out: HashMap<String, Arc<Vec<u8>>> = HashMap::new();

    let take = |gnosis: &str,
                hf_name: &str,
                out: &mut HashMap<String, Arc<Vec<u8>>>|
     -> Result<(), String> {
        let v = hf
            .get(hf_name)
            .ok_or_else(|| format!("map_hf_to_gnosis: missing HF tensor `{hf_name}`"))?;
        out.insert(gnosis.to_string(), Arc::new(f32_slice_to_le_bytes(v)));
        Ok(())
    };

    // ── Encoder stage tensors ───────────────────────────────────────────
    take(
        "encoder_conv1.weight",
        "model.encoder.conv1.weight",
        &mut out,
    )?;
    take("encoder_conv1.bias", "model.encoder.conv1.bias", &mut out)?;
    take(
        "encoder_conv2.weight",
        "model.encoder.conv2.weight",
        &mut out,
    )?;
    take("encoder_conv2.bias", "model.encoder.conv2.bias", &mut out)?;
    take(
        "encoder_pos_embed.weight",
        "model.encoder.embed_positions.weight",
        &mut out,
    )?;
    take(
        "encoder_ln_final.weight",
        "model.encoder.layer_norm.weight",
        &mut out,
    )?;
    take(
        "encoder_ln_final.bias",
        "model.encoder.layer_norm.bias",
        &mut out,
    )?;

    // ── Encoder blocks ──────────────────────────────────────────────────
    for i in 0..cfg.encoder_layers {
        let p = format!("model.encoder.layers.{i}");
        let g = format!("encoder_blk_{i}");
        take(
            &format!("{g}_attn_q.weight"),
            &format!("{p}.self_attn.q_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_attn_q.bias"),
            &format!("{p}.self_attn.q_proj.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_attn_k.weight"),
            &format!("{p}.self_attn.k_proj.weight"),
            &mut out,
        )?;
        // k_proj has no bias in Whisper.
        take(
            &format!("{g}_attn_v.weight"),
            &format!("{p}.self_attn.v_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_attn_v.bias"),
            &format!("{p}.self_attn.v_proj.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_attn_out.weight"),
            &format!("{p}.self_attn.out_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_attn_out.bias"),
            &format!("{p}.self_attn.out_proj.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_ln1.weight"),
            &format!("{p}.self_attn_layer_norm.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_ln1.bias"),
            &format!("{p}.self_attn_layer_norm.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_mlp_fc1.weight"),
            &format!("{p}.fc1.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_mlp_fc1.bias"),
            &format!("{p}.fc1.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_mlp_fc2.weight"),
            &format!("{p}.fc2.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_mlp_fc2.bias"),
            &format!("{p}.fc2.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_ln2.weight"),
            &format!("{p}.final_layer_norm.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_ln2.bias"),
            &format!("{p}.final_layer_norm.bias"),
            &mut out,
        )?;
    }

    // ── Decoder stage tensors ───────────────────────────────────────────
    take(
        "decoder_token_embed.weight",
        "model.decoder.embed_tokens.weight",
        &mut out,
    )?;
    take(
        "decoder_pos_embed.weight",
        "model.decoder.embed_positions.weight",
        &mut out,
    )?;
    take(
        "decoder_ln_final.weight",
        "model.decoder.layer_norm.weight",
        &mut out,
    )?;
    take(
        "decoder_ln_final.bias",
        "model.decoder.layer_norm.bias",
        &mut out,
    )?;

    // ── Decoder blocks ──────────────────────────────────────────────────
    for i in 0..cfg.decoder_layers {
        let p = format!("model.decoder.layers.{i}");
        let g = format!("decoder_blk_{i}");
        // self-attn
        take(
            &format!("{g}_self_q.weight"),
            &format!("{p}.self_attn.q_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_self_q.bias"),
            &format!("{p}.self_attn.q_proj.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_self_k.weight"),
            &format!("{p}.self_attn.k_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_self_v.weight"),
            &format!("{p}.self_attn.v_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_self_v.bias"),
            &format!("{p}.self_attn.v_proj.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_self_out.weight"),
            &format!("{p}.self_attn.out_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_self_out.bias"),
            &format!("{p}.self_attn.out_proj.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_self_ln.weight"),
            &format!("{p}.self_attn_layer_norm.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_self_ln.bias"),
            &format!("{p}.self_attn_layer_norm.bias"),
            &mut out,
        )?;
        // cross-attn
        take(
            &format!("{g}_cross_q.weight"),
            &format!("{p}.encoder_attn.q_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_cross_q.bias"),
            &format!("{p}.encoder_attn.q_proj.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_cross_k.weight"),
            &format!("{p}.encoder_attn.k_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_cross_v.weight"),
            &format!("{p}.encoder_attn.v_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_cross_v.bias"),
            &format!("{p}.encoder_attn.v_proj.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_cross_out.weight"),
            &format!("{p}.encoder_attn.out_proj.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_cross_out.bias"),
            &format!("{p}.encoder_attn.out_proj.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_cross_ln.weight"),
            &format!("{p}.encoder_attn_layer_norm.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_cross_ln.bias"),
            &format!("{p}.encoder_attn_layer_norm.bias"),
            &mut out,
        )?;
        // mlp
        take(
            &format!("{g}_mlp_fc1.weight"),
            &format!("{p}.fc1.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_mlp_fc1.bias"),
            &format!("{p}.fc1.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_mlp_fc2.weight"),
            &format!("{p}.fc2.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_mlp_fc2.bias"),
            &format!("{p}.fc2.bias"),
            &mut out,
        )?;
        take(
            &format!("{g}_mlp_ln.weight"),
            &format!("{p}.final_layer_norm.weight"),
            &mut out,
        )?;
        take(
            &format!("{g}_mlp_ln.bias"),
            &format!("{p}.final_layer_norm.bias"),
            &mut out,
        )?;
    }

    Ok(out)
}

// ─────────────────────────────────────────────────────────────────────────
// byte / dtype helpers
// ─────────────────────────────────────────────────────────────────────────

fn bytes_to_f32_vec(raw: &[u8]) -> Vec<f32> {
    let n = raw.len() / 4;
    let mut out = Vec::with_capacity(n);
    for i in 0..n {
        out.push(f32::from_le_bytes([
            raw[4 * i],
            raw[4 * i + 1],
            raw[4 * i + 2],
            raw[4 * i + 3],
        ]));
    }
    out
}

fn f16_bytes_to_f32_vec(raw: &[u8]) -> Vec<f32> {
    let n = raw.len() / 2;
    let mut out = Vec::with_capacity(n);
    for i in 0..n {
        out.push(f16_to_f32(u16::from_le_bytes([raw[2 * i], raw[2 * i + 1]])));
    }
    out
}

fn bf16_bytes_to_f32_vec(raw: &[u8]) -> Vec<f32> {
    // bf16 is the high 16 bits of an f32; shift back up.
    let n = raw.len() / 2;
    let mut out = Vec::with_capacity(n);
    for i in 0..n {
        let bits = u16::from_le_bytes([raw[2 * i], raw[2 * i + 1]]);
        out.push(f32::from_bits((bits as u32) << 16));
    }
    out
}

fn f16_to_f32(h: u16) -> f32 {
    let sign = (h >> 15) & 1;
    let exp = (h >> 10) & 0x1f;
    let mant = h & 0x3ff;
    let f = match exp {
        0 => {
            if mant == 0 {
                (sign as u32) << 31
            } else {
                let mut e = -1i32;
                let mut m = mant as u32;
                loop {
                    e += 1;
                    m <<= 1;
                    if m & 0x400 != 0 {
                        break;
                    }
                }
                let m = m & 0x3ff;
                ((sign as u32) << 31) | (((127 - 15 - e) as u32) << 23) | (m << 13)
            }
        }
        0x1f => ((sign as u32) << 31) | (0xff << 23) | ((mant as u32) << 13),
        _ => {
            ((sign as u32) << 31) | (((exp as i32 - 15 + 127) as u32) << 23) | ((mant as u32) << 13)
        }
    };
    f32::from_bits(f)
}

fn f32_slice_to_le_bytes(v: &[f32]) -> Vec<u8> {
    let mut out = Vec::with_capacity(v.len() * 4);
    for &x in v {
        out.extend_from_slice(&x.to_le_bytes());
    }
    out
}
